def solution(pence: int = 200):
    coins = [1, 2, 5, 10, 20, 50, 100, 200]
    ways = [0] * (pence + 1)
    ways[0] = 1 # One way to make 0p (using no coins)

    # Outer loop should be over coins to ensure we only count combinations
    for coin in coins:
        for amount in range(coin, pence + 1):
            ways[amount] += ways[amount - coin]

    return ways[pence]


if __name__ == "__main__":
    print(solution(200))
